INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('heelevel3-5ff21eeb-moex-00284', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-110-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '依稅捐稽徵法關於延期或分期繳納申請之規定，下列何者錯誤？', '["納稅義務人只有遇到天災、事變、不可抗力之事由致其不能於法定期間內繳清稅捐者，才能申 請延期或分期繳納", "經依稅捐稽徵法第10條或第26條核准延期或分期繳納者，才可以免加計利息", "延期或分期繳納之期間，不得逾3年", "納稅義務人對核准延期或分期繳納之任何一期應繳稅捐，未如期繳納者，稅捐稽徵機關應就未 繳清之餘額稅款，限10日內一次全部繳清"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:09+00:00", "source_pdf_sha1": "314308e70f57", "answer_pdf_sha1": "ddd919f3bec4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00285', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-110-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '依稅捐稽徵法有關稅捐核課期間之規定，下列敘述何者錯誤？', '["如已逾核課期間，稅捐稽徵機關即不得再補稅處罰", "稅捐罰鍰案件，其罰鍰裁處期間可以準用稅捐核課期間之規定，視其有無故意以詐欺或其他不 正當方法逃漏稅捐，分別認定為5年或7年", "稅捐稽徵機關只須將稅款繳款書於稅捐核課期間內發出即無違背核課期間之規定", "稅捐稽徵機關須將稅款繳款書於稅捐核課期間內發出並送達相對人，始無違背核課期間之規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:09+00:00", "source_pdf_sha1": "314308e70f57", "answer_pdf_sha1": "ddd919f3bec4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00286', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-110-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '乙君欠繳A屋及其坐落土地108年度房屋稅新臺幣（下同）10萬元、108年度地價稅5萬元，以 及欠繳106年度綜合所得稅100萬元及贈與稅罰鍰20萬元，另乙君A屋及其坐落土地上設有抵 押權擔保債權200萬元未清償。上述乙君欠繳之稅捐經稅捐稽徵機關移送強制執行後，行政執行 機關拍賣該A屋及其坐落土地，該土地增值稅為20萬元，A屋及其坐落土地抵押債權人參與分 配200萬元，拍得價金經扣除執行費用後為200萬元，稅捐稽徵機關受償金額為何？', '["0元", "35萬元", "155萬元", "135萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:09+00:00", "source_pdf_sha1": "314308e70f57", "answer_pdf_sha1": "ddd919f3bec4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00287', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-110-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '中央主管機關應每幾年檢視解釋函令有無違反法律之規定、意旨，或增加法律所無之納稅義務？', '["1年", "2年", "3年", "4年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:09+00:00", "source_pdf_sha1": "314308e70f57", "answer_pdf_sha1": "ddd919f3bec4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00288', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-110-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '下列何種情形，稅捐稽徵人員對於納稅義務人之財產、所得、營業、納稅等資料在以下情況，得', '["債權人持金錢給付之確定判決，向稅捐稽徵機關申請查調判決所載債務人之財產資料", "債權人持拍賣抵押物裁定，向稅捐稽徵機關申請查調該抵押人之所得資料", "政府機關因公務 需要，經財政部核定後函請稅捐稽徵機關提供納稅義務人所得資料", "地價稅代繳義務人向稅捐 稽徵機關申請提供代繳稅款之土地稅資料 ⑤大專院校為教學或研究目的，向稅捐稽徵機關申請 提供不洩漏納稅義務人之姓名或名稱，且符合政府資訊公開法規定者之財稅資料"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:09+00:00", "source_pdf_sha1": "314308e70f57", "answer_pdf_sha1": "ddd919f3bec4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00289', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-110-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '甲君知悉其所有作農業使用之農地即將徵收，遂於徵收前將農地贈與其子乙君，並申報贈與稅。 有關租稅規避之敘述，下列何者為錯誤？', '["甲君知悉其所採取之安排，實際上係為使乙君獲取徵收補償金並免除贈與稅，符合租稅規避之 主觀構成要件", "甲君利用遺產及贈與稅法第20條第1項第5款贈與農地不計入贈與總額之規定，合法贈與乙 君而發生獲取徵收補償金並免除贈與稅之結果，客觀上濫用法律形式，使乙君取得非立法者當 時所預期給予之稅捐利益", "稅捐稽徵機關查獲甲君涉有租稅規避情事，嗣甲君對於重要事項提供不正確資料，致稅捐稽徵 機關短漏核定稅捐，對甲君除應補稅處罰外，並應另加徵租稅規避之滯納金及利息", "稅捐稽徵機關就甲君有租稅規避情事而符合課徵贈與稅之構成要件事實，負有舉證責任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:09+00:00", "source_pdf_sha1": "314308e70f57", "answer_pdf_sha1": "ddd919f3bec4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00290', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-110-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '稅捐稽徵機關為行使核課權之必要，調查甲君買賣房地之交易情形，經甲君委任乙君為代理人。', '["稅捐稽徵機關請甲君提供相關交易資料到場備 詢，原則上應以書面方式為之，並應載明調查事由及範圍，同時給予甲君準備資料之合理期間", "甲君依調查函所載期日到場備詢，因代理人乙君尚未到場，甲君得拒絕接受調查", "在進行調 查前，甲君告知稅捐稽徵機關其自行就調查過程全程進行錄影、錄音，稅捐稽徵機關得一律拒絕 之", "稅捐稽徵機關於進行調查後，另收受通報資料，認甲君有再為調查之必要時，前次已依法 以書面通知備詢，因屬同一調查程序，本次通知備詢不以書面為限"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:09+00:00", "source_pdf_sha1": "314308e70f57", "answer_pdf_sha1": "ddd919f3bec4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00291', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-110-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '甲君從事網路銷售服飾，經稅捐稽徵機關查獲涉有逃漏營業稅之情事，乃通知甲君說明及提示相', '["稅捐稽徵機關已掌握貨運資 料，惟就全部實際銷售金額經調查仍不能確定，為維護課稅公平原則，得推計課稅", "稅捐稽徵 機關推計課稅，應斟酌與推計具有關聯性之一切重要事項，依合理客觀之程序及適切之方式為之", "稅捐稽徵機關就計算甲銷售金額有二種以上推計方法，雖稅法已有明定推計方法，為維護課稅 公平原則及核實課稅原則，仍應依納稅者權利保護法第 14 條第 3 項規定，以最切近實額之方法 為之", "稅捐稽徵機關掌握甲確有銷售服飾之事實，惟無法查得實際銷售金額，依處罰明確性原 則，不得以推計結果對甲處以漏稅罰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:09+00:00", "source_pdf_sha1": "314308e70f57", "answer_pdf_sha1": "ddd919f3bec4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00292', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-110-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '有關納稅者權利保護官應辦理事項或職權內容，下列敘述何者為錯誤？', '["稅捐稽徵機關為便利納稅者尋求協助，稅捐稽徵機關應於網站公告納稅者權利保護官之姓名及 聯絡方式", "納稅者權利保護官係由稅捐稽徵機關以任務編組方式指定專人為之，辦理協助納稅者進行稅捐 爭議之溝通與協調、受理納稅者之申訴或陳情並提出改善建議、於納稅者依法尋求救濟時提供 必要之諮詢與協助等事項", "納稅者權利保護官制度屬訴訟外紛爭解決機制，納稅者如就核定稅捐處分不服，得自行選擇尋求 納稅者權利保護官協助，或依法提起行政救濟，但僅得擇一行使其權利，以避免結果發生歧異", "納稅者權利保護官於辦理納稅者權利保護事項，得為必要之調查"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:09+00:00", "source_pdf_sha1": "314308e70f57", "answer_pdf_sha1": "ddd919f3bec4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00293', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-110-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '依納稅者權利保護法有關租稅規避行為之規定，下列敘述何者正確？', '["稽徵機關發現納稅義務人有租稅規避行為，只需加徵滯納金及利息即可", "稽徵機關發現納稅義務人有租稅規避行為，除加徵滯納金及利息外，亦需補稅", "稽徵機關發現納稅義務人有租稅規避行為，即應課予逃漏稅捐之處罰", "納稅者權利保護法施行前之租稅規避案件，已裁罰尚未確定者，仍適用原裁罰金額，不受該法 施行之影響"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:09+00:00", "source_pdf_sha1": "314308e70f57", "answer_pdf_sha1": "ddd919f3bec4", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL)
